    24Ôćĺfunc Auth(store KeyStore, sessions SessionValidator) Middleware {
    25Ôćĺ	return func(next http.Handler) http.Handler {
    26Ôćĺ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    27Ôćĺ			// Try Bearer token first
    28Ôćĺ			if header := r.Header.Get("Authorization"); strings.HasPrefix(header, "Bearer ") {
    29Ôćĺ				rawKey := strings.TrimPrefix(header, "Bearer ")
    30Ôćĺ				valid, err := store.ValidateKey(r.Context(), rawKey)
    31Ôćĺ				if err != nil || !valid {
    32Ôćĺ					RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Invalid API key")
    33Ôćĺ					return
    34Ôćĺ				}
    35Ôćĺ				go store.TouchKeyUsage(context.Background(), rawKey)
    36Ôćĺ				next.ServeHTTP(w, r)
    37Ôćĺ				return
    38Ôćĺ			}
    39Ôćĺ
    40Ôćĺ			// Try session cookie
    41Ôćĺ			if sessions != nil {
    42Ôćĺ				if c, err := r.Cookie("session"); err == nil {
    43Ôćĺ					u, err := sessions.ValidateSession(r.Context(), c.Value)
    44Ôćĺ					if err == nil {
    45Ôćĺ						next.ServeHTTP(w, r.WithContext(auth.WithUser(r.Context(), u)))
    46Ôćĺ						return
    47Ôćĺ					}
    48Ôćĺ				}
    49Ôćĺ			}
    50Ôćĺ
    51Ôćĺ			RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Missing API key")
    52Ôćĺ		})
    53Ôćĺ	}
    54Ôćĺ}
