    56Ôćĺfunc RateLimit(rps float64, burst int) Middleware {
    57Ôćĺ	var mu sync.Mutex
    58Ôćĺ	limiters := make(map[string]*rate.Limiter)
    59Ôćĺ	getLimiter := func(key string) *rate.Limiter {
    60Ôćĺ		mu.Lock()
    61Ôćĺ		defer mu.Unlock()
    62Ôćĺ		if lim, ok := limiters[key]; ok {
    63Ôćĺ			return lim
    64Ôćĺ		}
    65Ôćĺ		lim := rate.NewLimiter(rate.Limit(rps), burst)
    66Ôćĺ		limiters[key] = lim
    67Ôćĺ		return lim
    68Ôćĺ	}
    69Ôćĺ	return func(next http.Handler) http.Handler {
    70Ôćĺ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    71Ôćĺ			key := r.RemoteAddr
    72Ôćĺ			if auth := r.Header.Get("Authorization"); strings.HasPrefix(auth, "Bearer ") {
    73Ôćĺ				key = strings.TrimPrefix(auth, "Bearer ")
    74Ôćĺ			}
    75Ôćĺ			lim := getLimiter(key)
    76Ôćĺ			if !lim.Allow() {
    77Ôćĺ				w.Header().Set("Retry-After", "1")
    78Ôćĺ				RespondError(w, r, http.StatusTooManyRequests, "rate_limited", "Too many requests")
    79Ôćĺ				return
    80Ôćĺ			}
    81Ôćĺ			next.ServeHTTP(w, r)
    82Ôćĺ		})
    83Ôćĺ	}
    84Ôćĺ}
