    15Ôćĺ// OAuthHandler handles GitHub OAuth flow and session endpoints.
    16Ôćĺtype OAuthHandler struct {
    17Ôćĺ	ClientID     string
    18Ôćĺ	ClientSecret string
    19Ôćĺ	Pool         *pgxpool.Pool
    20Ôćĺ	Sessions     *SessionStore
    21Ôćĺ	States       *StateStore
    22Ôćĺ	Allowlist    *Allowlist
    23Ôćĺ	SecureCookie bool
