    28Ôćĺ// HandleGitHubRedirect redirects to GitHub's OAuth authorize URL.
    29Ôćĺfunc (h *OAuthHandler) HandleGitHubRedirect(w http.ResponseWriter, r *http.Request) {
    30Ôćĺ	state := h.States.Create()
    31Ôćĺ	if state == "" {
    32Ôćĺ		http.Error(w, "too many pending login requests", http.StatusTooManyRequests)
    33Ôćĺ		return
    34Ôćĺ	}
    35Ôćĺ
    36Ôćĺ	params := url.Values{
    37Ôćĺ		"client_id":    {h.ClientID},
    38Ôćĺ		"state":        {state},
    39Ôćĺ		"scope":        {"read:org"},
    40Ôćĺ		"redirect_uri": {callbackURL(r, h.FrontendURL)},
    41Ôćĺ	}
    42Ôćĺ	http.Redirect(w, r, "https://github.com/login/oauth/authorize?"+params.Encode(), http.StatusFound)
    43Ôćĺ}
