    45Ôćĺ// HandleGitHubCallback handles the OAuth callback from GitHub.
    46Ôćĺfunc (h *OAuthHandler) HandleGitHubCallback(w http.ResponseWriter, r *http.Request) {
    47Ôćĺ	// Validate state
    48Ôćĺ	state := r.URL.Query().Get("state")
    49Ôćĺ	if !h.States.Consume(state) {
    50Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=invalid_state"), http.StatusFound)
    51Ôćĺ		return
    52Ôćĺ	}
    53Ôćĺ
    54Ôćĺ	code := r.URL.Query().Get("code")
    55Ôćĺ	if code == "" {
    56Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=missing_code"), http.StatusFound)
    57Ôćĺ		return
    58Ôćĺ	}
    59Ôćĺ
    60Ôćĺ	client := h.HTTPClient
    61Ôćĺ	if client == nil {
    62Ôćĺ		client = http.DefaultClient
    63Ôćĺ	}
    64Ôćĺ
    65Ôćĺ	// Exchange code for access token
    66Ôćĺ	token, err := exchangeCode(client, h.ClientID, h.ClientSecret, code)
    67Ôćĺ	if err != nil {
    68Ôćĺ		slog.Error("github token exchange failed", "err", err)
    69Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=token_exchange"), http.StatusFound)
    70Ôćĺ		return
    71Ôćĺ	}
    72Ôćĺ
    73Ôćĺ	// Fetch user info
    74Ôćĺ	ghUser, err := fetchGitHubUser(client, token)
    75Ôćĺ	if err != nil {
    76Ôćĺ		slog.Error("github user fetch failed", "err", err)
    77Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=user_fetch"), http.StatusFound)
    78Ôćĺ		return
    79Ôćĺ	}
    80Ôćĺ
    81Ôćĺ	// Fetch user orgs
    82Ôćĺ	orgs, err := fetchGitHubOrgs(client, token)
    83Ôćĺ	if err != nil {
    84Ôćĺ		slog.Warn("github orgs fetch failed, proceeding without orgs", "err", err)
    85Ôćĺ	}
    86Ôćĺ
    87Ôćĺ	// Check allowlist
    88Ôćĺ	orgLogins := make([]string, len(orgs))
    89Ôćĺ	for i, o := range orgs {
    90Ôćĺ		orgLogins[i] = o.Login
    91Ôćĺ	}
    92Ôćĺ	if !h.Allowlist.IsUserAllowed(ghUser.Login, orgLogins) {
    93Ôćĺ		slog.Warn("login denied: user not in allowlist", "login", ghUser.Login, "orgs", orgLogins)
    94Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=unauthorized"), http.StatusFound)
    95Ôćĺ		return
    96Ôćĺ	}
    97Ôćĺ
    98Ôćĺ	// Upsert user
    99Ôćĺ	var userID string
   100Ôćĺ	err = h.Pool.QueryRow(r.Context(), `
   101Ôćĺ		INSERT INTO users (github_id, github_login, name, avatar_url)
   102Ôćĺ		VALUES ($1, $2, $3, $4)
   103Ôćĺ		ON CONFLICT (github_id) DO UPDATE SET
   104Ôćĺ			github_login = EXCLUDED.github_login,
   105Ôćĺ			name = EXCLUDED.name,
   106Ôćĺ			avatar_url = EXCLUDED.avatar_url,
   107Ôćĺ			updated_at = NOW()
   108Ôćĺ		RETURNING id
   109Ôćĺ	`, ghUser.ID, ghUser.Login, ghUser.Name, ghUser.AvatarURL).Scan(&userID)
   110Ôćĺ	if err != nil {
   111Ôćĺ		slog.Error("user upsert failed", "err", err)
   112Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=server_error"), http.StatusFound)
   113Ôćĺ		return
   114Ôćĺ	}
   115Ôćĺ
   116Ôćĺ	// Create session
   117Ôćĺ	cookie, expiresAt, err := h.Sessions.CreateSession(r.Context(), userID)
   118Ôćĺ	if err != nil {
   119Ôćĺ		slog.Error("session creation failed", "err", err)
   120Ôćĺ		http.Redirect(w, r, h.frontendURL("/login?error=server_error"), http.StatusFound)
   121Ôćĺ		return
   122Ôćĺ	}
   123Ôćĺ
   124Ôćĺ	slog.Info("user logged in", "login", ghUser.Login, "user_id", userID)
   125Ôćĺ
   126Ôćĺ	http.SetCookie(w, &http.Cookie{
   127Ôćĺ		Name:     "session",
   128Ôćĺ		Value:    cookie,
   129Ôćĺ		Path:     "/",
   130Ôćĺ		Expires:  expiresAt,
   131Ôćĺ		HttpOnly: true,
   132Ôćĺ		Secure:   h.SecureCookie,
   133Ôćĺ		SameSite: http.SameSiteLaxMode,
   134Ôćĺ	})
   135Ôćĺ	http.Redirect(w, r, h.frontendURL("/"), http.StatusFound)
   136Ôćĺ}
