   174Ôćĺ// RequireSession is middleware that loads the user from the session cookie into context.
   175Ôćĺfunc (h *OAuthHandler) RequireSession(next http.Handler) http.Handler {
   176Ôćĺ	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   177Ôćĺ		c, err := r.Cookie("session")
   178Ôćĺ		if err != nil {
   179Ôćĺ			http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)
   180Ôćĺ			return
   181Ôćĺ		}
   182Ôćĺ		u, err := h.Sessions.ValidateSession(r.Context(), c.Value)
   183Ôćĺ		if err != nil {
   184Ôćĺ			http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)
   185Ôćĺ			return
   186Ôćĺ		}
   187Ôćĺ		next.ServeHTTP(w, r.WithContext(WithUser(r.Context(), u)))
   188Ôćĺ	})
   189Ôćĺ}
