   204Ôćĺfunc exchangeCode(client *http.Client, clientID, clientSecret, code string) (string, error) {
   205Ôćĺ	data := url.Values{
   206Ôćĺ		"client_id":     {clientID},
   207Ôćĺ		"client_secret": {clientSecret},
   208Ôćĺ		"code":          {code},
   209Ôćĺ	}
   210Ôćĺ	req, _ := http.NewRequest(http.MethodPost, "https://github.com/login/oauth/access_token", strings.NewReader(data.Encode()))
   211Ôćĺ	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
   212Ôćĺ	req.Header.Set("Accept", "application/json")
   213Ôćĺ
   214Ôćĺ	resp, err := client.Do(req)
   215Ôćĺ	if err != nil {
   216Ôćĺ		return "", fmt.Errorf("token request: %w", err)
   217Ôćĺ	}
   218Ôćĺ	defer resp.Body.Close()
   219Ôćĺ
   220Ôćĺ	var result struct {
   221Ôćĺ		AccessToken string `json:"access_token"`
   222Ôćĺ		Error       string `json:"error"`
   223Ôćĺ	}
   224Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
   225Ôćĺ		return "", fmt.Errorf("decode token response: %w", err)
   226Ôćĺ	}
   227Ôćĺ	if result.Error != "" {
   228Ôćĺ		return "", fmt.Errorf("github error: %s", result.Error)
   229Ôćĺ	}
   230Ôćĺ	if result.AccessToken == "" {
   231Ôćĺ		return "", fmt.Errorf("empty access token")
   232Ôćĺ	}
   233Ôćĺ	return result.AccessToken, nil
   234Ôćĺ}
