   236Ôćĺfunc fetchGitHubUser(client *http.Client, token string) (*githubUser, error) {
   237Ôćĺ	req, _ := http.NewRequest(http.MethodGet, "https://api.github.com/user", nil)
   238Ôćĺ	req.Header.Set("Authorization", "Bearer "+token)
   239Ôćĺ	req.Header.Set("Accept", "application/json")
   240Ôćĺ
   241Ôćĺ	resp, err := client.Do(req)
   242Ôćĺ	if err != nil {
   243Ôćĺ		return nil, err
   244Ôćĺ	}
   245Ôćĺ	defer resp.Body.Close()
   246Ôćĺ	if resp.StatusCode != http.StatusOK {
   247Ôćĺ		body, _ := io.ReadAll(resp.Body)
   248Ôćĺ		return nil, fmt.Errorf("github /user returned %d: %s", resp.StatusCode, body)
   249Ôćĺ	}
   250Ôćĺ
   251Ôćĺ	var u githubUser
   252Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&u); err != nil {
   253Ôćĺ		return nil, err
   254Ôćĺ	}
   255Ôćĺ	return &u, nil
   256Ôćĺ}
