   266Ôćĺ	}
   267Ôćĺ	defer resp.Body.Close()
   268Ôćĺ	if resp.StatusCode != http.StatusOK {
   269Ôćĺ		return nil, fmt.Errorf("github /user/orgs returned %d", resp.StatusCode)
   270Ôćĺ	}
   271Ôćĺ
   272Ôćĺ	var orgs []githubOrg
   273Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&orgs); err != nil {
   274Ôćĺ		return nil, err
   275Ôćĺ	}
   276Ôćĺ	return orgs, nil
