   279Ôćĺfunc callbackURL(r *http.Request, frontendURL string) string {
   280Ôćĺ	// When a frontend URL is configured (dev with separate frontend port),
   281Ôćĺ	// use it so the GitHub callback goes through the frontend proxy and the
   282Ôćĺ	// session cookie is set on the correct origin.
   283Ôćĺ	if frontendURL != "" {
   284Ôćĺ		return strings.TrimRight(frontendURL, "/") + "/auth/github/callback"
   285Ôćĺ	}
   286Ôćĺ	scheme := "https"
   287Ôćĺ	if r.TLS == nil {
   288Ôćĺ		scheme = "http"
   289Ôćĺ	}
   290Ôćĺ	if fwd := r.Header.Get("X-Forwarded-Proto"); fwd != "" {
   291Ôćĺ		scheme = fwd
   292Ôćĺ	}
   293Ôćĺ	return scheme + "://" + r.Host + "/auth/github/callback"
   294Ôćĺ}
