    10Ôćĺ
    11Ôćĺ// Orchestrator runs polling ingestion sources on a fixed interval.
    12Ôćĺtype Orchestrator struct {
    13Ôćĺ	service       *Service
    14Ôćĺ	loader        *SourceLoader
    15Ôćĺ	pool          *pgxpool.Pool
    16Ôćĺ	staticSources []IIngestionSource // for testing only
    17Ôćĺ	interval      time.Duration
    18Ôćĺ}
    19Ôćĺ
    20Ôćĺ// NewOrchestrator creates an orchestrator that dynamically loads enabled
    21Ôćĺ// sources from the database on each poll cycle.
    22Ôćĺfunc NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
    23Ôćĺ	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
    24Ôćĺ}
    25Ôćĺ
    26Ôćĺ// NewOrchestratorWithSources creates an orchestrator with a static source list.
    27Ôćĺ// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
    28Ôćĺfunc NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
    29Ôćĺ	return &Orchestrator{service: service, staticSources: sources, interval: interval}
    30Ôćĺ}
    31Ôćĺ
    32Ôćĺ// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
    33Ôćĺfunc (o *Orchestrator) Run(ctx context.Context) {
    34Ôćĺ	ticker := time.NewTicker(o.interval)
