    39Ôćĺ	for {
    40Ôćĺ		select {
    41Ôćĺ		case <-ctx.Done():
    42Ôćĺ			return
    43Ôćĺ		case <-ticker.C:
    44Ôćĺ			o.pollAll(ctx)
    45Ôćĺ		}
    46Ôćĺ	}
    47Ôćĺ}
