    52Ôćĺ		scheduled, err := o.loader.LoadEnabledSources(ctx)
    53Ôćĺ		if err != nil {
    54Ôćĺ			slog.Error("load sources failed", "err", err)
    55Ôćĺ			return
    56Ôćĺ		}
    57Ôćĺ		if len(scheduled) == 0 {
    58Ôćĺ			slog.Debug("no enabled sources to poll")
    59Ôćĺ			return
    60Ôćĺ		}
    61Ôćĺ		now := time.Now()
