    68Ôćĺ			}
    69Ôćĺ			o.pollSource(ctx, ss.Source)
    70Ôćĺ		}
    71Ôćĺ		return
    72Ôćĺ	}
    73Ôćĺ	if len(sources) == 0 {
    74Ôćĺ		slog.Debug("no enabled sources to poll")
    75Ôćĺ		return
    76Ôćĺ	}
    77Ôćĺ	for _, src := range sources {
    78Ôćĺ		o.pollSource(ctx, src)
    79Ôćĺ	}
    80Ôćĺ}
    81Ôćĺ
    82Ôćĺfunc (o *Orchestrator) pollSource(ctx context.Context, src IIngestionSource) {
    83Ôćĺ	results, err := src.FetchNewReleases(ctx)
