    85Ôćĺ		slog.Error("poll failed", "source", src.Name(), "err", err)
    86Ôćĺ		o.updateSourcePollStatus(ctx, src.SourceID(), err)
    87Ôćĺ		return
    88Ôćĺ	}
    89Ôćĺ	o.updateSourcePollStatus(ctx, src.SourceID(), nil)
    90Ôćĺ	if len(results) == 0 {
    91Ôćĺ		return
    92Ôćĺ	}
    93Ôćĺ	if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
    94Ôćĺ		slog.Error("process failed", "source", src.Name(), "err", err)
    95Ôćĺ	}
    96Ôćĺ}
    97Ôćĺ
    98Ôćĺfunc (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
    99Ôćĺ	if o.pool == nil {
   100Ôćĺ		return
   101Ôćĺ	}
   102Ôćĺ	var lastError *string
   103Ôćĺ	if pollErr != nil {
   104Ôćĺ		s := pollErr.Error()
   105Ôćĺ		lastError = &s
   106Ôćĺ	}
   107Ôćĺ	_, err := o.pool.Exec(ctx,
   108Ôćĺ		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
   109Ôćĺ		lastError, sourceID)
   110Ôćĺ	if err != nil {
   111Ôćĺ		slog.Error("update source poll status", "source", sourceID, "err", err)
   112Ôćĺ	}
   113Ôćĺ}
