    46Ôćĺ}) {
    47Ôćĺ  const measureRef = useRef<HTMLDivElement>(null);
    48Ôćĺ  const moreRef = useRef<HTMLSpanElement>(null);
    49Ôćĺ  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    50Ôćĺ
    51Ôćĺ  const items = React.Children.toArray(children);
    52Ôćĺ
    53Ôćĺ  const measure = useCallback(() => {
    54Ôćĺ    const el = measureRef.current;
    55Ôćĺ    if (!el) return;
    56Ôćĺ    const nodes = el.children;
    57Ôćĺ    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "moreÔÇŽ" span (last)
    58Ôćĺ    // Check if everything fits without overflow
    59Ôćĺ    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    60Ôćĺ      setVisibleCount(items.length);
    61Ôćĺ      return;
    62Ôćĺ    }
    63Ôćĺ    // Measure actual "moreÔÇŽ" link width
    64Ôćĺ    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    65Ôćĺ    const containerWidth = el.offsetWidth;
    66Ôćĺ    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    67Ôćĺ    let lastFitting = 0;
    68Ôćĺ    for (let i = 1; i <= itemNodeCount; i++) {
    69Ôćĺ      const node = nodes[i] as HTMLElement;
    70Ôćĺ      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    71Ôćĺ      lastFitting = i;
    72Ôćĺ    }
    73Ôćĺ    // Second pass: walk backward from lastFitting until "moreÔÇŽ" fits after the item
    74Ôćĺ    let count = lastFitting;
    75Ôćĺ    while (count > 1) {
    76Ôćĺ      const node = nodes[count] as HTMLElement;
    77Ôćĺ      const nodeBottom = node.offsetTop + node.offsetHeight;
    78Ôćĺ      // If this item is on line 1, "moreÔÇŽ" can always wrap to line 2 ÔÇö we're fine
    79Ôćĺ      if (nodeBottom <= LINE_HEIGHT) break;
    80Ôćĺ      // Item is on line 2 ÔÇö check if "moreÔÇŽ" fits after it on the same line
    81Ôćĺ      const nodeRight = node.offsetLeft + node.offsetWidth;
    82Ôćĺ      if (nodeRight + moreWidth <= containerWidth) break;
    83Ôćĺ      count--;
    84Ôćĺ    }
    85Ôćĺ    setVisibleCount(Math.max(1, count));
    86Ôćĺ  }, [items.length]);
    87Ôćĺ
    88Ôćĺ  useEffect(() => {
    89Ôćĺ    const raf = requestAnimationFrame(measure);
    90Ôćĺ    const obs = new ResizeObserver(measure);
    91Ôćĺ    if (measureRef.current) obs.observe(measureRef.current);
    92Ôćĺ    return () => {
    93Ôćĺ      cancelAnimationFrame(raf);
    94Ôćĺ      obs.disconnect();
    95Ôćĺ    };
    96Ôćĺ  }, [measure, items.length]);
    97Ôćĺ
    98Ôćĺ  const hasOverflow = visibleCount !== null && visibleCount < items.length;
    99Ôćĺ  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   100Ôćĺ
   101Ôćĺ  return (
   102Ôćĺ    <div className="relative">
   103Ôćĺ      {/* Hidden measurer ÔÇö renders all items to find cutoff */}
   104Ôćĺ      <div
   105Ôćĺ        ref={measureRef}
   106Ôćĺ        className="text-[13px] leading-7"
   107Ôćĺ        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   108Ôćĺ        aria-hidden="true"
   109Ôćĺ      >
   110Ôćĺ        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   111Ôćĺ          {label}:
   112Ôćĺ        </span>
   113Ôćĺ        {items}
   114Ôćĺ        {/* Hidden "moreÔÇŽ" to measure its actual width */}
   115Ôćĺ        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   116Ôćĺ          moreÔÇŽ
   117Ôćĺ        </span>
   118Ôćĺ      </div>
   119Ôćĺ      {/* Visible section */}
   120Ôćĺ      <div className="text-[13px] leading-7">
   121Ôćĺ        <span
   122Ôćĺ          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   123Ôćĺ          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   124Ôćĺ        >
   125Ôćĺ          {label}:
   126Ôćĺ        </span>
   127Ôćĺ        {displayed}
   128Ôćĺ        {hasOverflow && (
   129Ôćĺ          <Link
   130Ôćĺ            href={moreHref}
   131Ôćĺ            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   132Ôćĺ            style={{ color: "#e8601a" }}
   133Ôćĺ          >
   134Ôćĺ            moreÔÇŽ
   135Ôćĺ          </Link>
   136Ôćĺ        )}
   137Ôćĺ      </div>
   138Ôćĺ    </div>
   139Ôćĺ  );
   140Ôćĺ}
