    33Ôćĺfunc (s *DockerHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    34Ôćĺ	url := fmt.Sprintf("%s/v2/repositories/%s/tags/?page_size=25&ordering=last_updated",
    35Ôćĺ		s.baseURL, s.repository)
    36Ôćĺ
    37Ôćĺ	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    38Ôćĺ	if err != nil {
    39Ôćĺ		return nil, fmt.Errorf("create request: %w", err)
    40Ôćĺ	}
    41Ôćĺ
    42Ôćĺ	resp, err := s.client.Do(req)
    43Ôćĺ	if err != nil {
    44Ôćĺ		return nil, fmt.Errorf("fetch tags: %w", err)
    45Ôćĺ	}
    46Ôćĺ	defer resp.Body.Close()
    47Ôćĺ
    48Ôćĺ	if resp.StatusCode != http.StatusOK {
    49Ôćĺ		return nil, httpStatusError(resp)
    50Ôćĺ	}
    51Ôćĺ
    52Ôćĺ	var body struct {
    53Ôćĺ		Results []struct {
    54Ôćĺ			Name        string `json:"name"`
    55Ôćĺ			LastUpdated string `json:"last_updated"`
    56Ôćĺ		} `json:"results"`
    57Ôćĺ	}
    58Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
    59Ôćĺ		return nil, fmt.Errorf("decode response: %w", err)
    60Ôćĺ	}
    61Ôćĺ
    62Ôćĺ	results := make([]IngestionResult, 0, len(body.Results))
    63Ôćĺ	for _, tag := range body.Results {
    64Ôćĺ		ts, _ := time.Parse(time.RFC3339Nano, tag.LastUpdated)
