    66Ôćĺ			Repository: s.repository,
    67Ôćĺ			RawVersion: tag.Name,
    68Ôćĺ			Timestamp:  ts,
    69Ôćĺ		})
    70Ôćĺ	}
    71Ôćĺ	return results, nil
    72Ôćĺ}
