    44Ôćĺfunc (s *GitHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    45Ôćĺ	url := fmt.Sprintf("%s/repos/%s/releases?per_page=30", s.baseURL, s.repository)
    46Ôćĺ
    47Ôćĺ	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    48Ôćĺ	if err != nil {
    49Ôćĺ		return nil, fmt.Errorf("create request: %w", err)
    50Ôćĺ	}
    51Ôćĺ	req.Header.Set("Accept", "application/vnd.github+json")
    52Ôćĺ
    53Ôćĺ	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
    54Ôćĺ		req.Header.Set("Authorization", "Bearer "+token)
    55Ôćĺ	}
    56Ôćĺ
    57Ôćĺ	resp, err := s.client.Do(req)
    58Ôćĺ	if err != nil {
    59Ôćĺ		return nil, fmt.Errorf("fetch releases: %w", err)
    60Ôćĺ	}
    61Ôćĺ	defer resp.Body.Close()
    62Ôćĺ
    63Ôćĺ	if resp.StatusCode != http.StatusOK {
    64Ôćĺ		return nil, httpStatusError(resp)
    65Ôćĺ	}
    66Ôćĺ
    67Ôćĺ	var releases []ghRelease
    68Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
    69Ôćĺ		return nil, fmt.Errorf("decode releases: %w", err)
    70Ôćĺ	}
    71Ôćĺ
    72Ôćĺ	results := make([]IngestionResult, 0, len(releases))
    73Ôćĺ	for _, rel := range releases {
    74Ôćĺ		if rel.Draft {
    75Ôćĺ			continue
    76Ôćĺ		}
    77Ôćĺ		if rel.TagName == "" {
    78Ôćĺ			continue
    79Ôćĺ		}
    80Ôćĺ
    81Ôćĺ		ts, _ := time.Parse(time.RFC3339, rel.PublishedAt)
    82Ôćĺ
    83Ôćĺ		prerelease := "false"
    84Ôćĺ		if rel.Prerelease {
    85Ôćĺ			prerelease = "true"
    86Ôćĺ		}
    87Ôćĺ
    88Ôćĺ		results = append(results, IngestionResult{
    89Ôćĺ			Repository: s.repository,
    90Ôćĺ			RawVersion: rel.TagName,
    91Ôćĺ			Changelog:  rel.Body,
    92Ôćĺ			Metadata: map[string]string{
    93Ôćĺ				"release_url": rel.HTMLURL,
    94Ôćĺ				"prerelease":  prerelease,
    95Ôćĺ			},
    96Ôćĺ			Timestamp: ts,
    97Ôćĺ		})
    98Ôćĺ	}
    99Ôćĺ	return results, nil
   100Ôćĺ}
