    10Ôćĺ	"github.com/jackc/pgx/v5/pgxpool"
    11Ôćĺ	"github.com/riverqueue/river"
    12Ôćĺ	"github.com/sentioxyz/changelogue/internal/queue"
    13Ôćĺ)
    14Ôćĺ
    15Ôćĺ// PgStore implements ReleaseStore using PostgreSQL + River for the transactional outbox.
    16Ôćĺtype PgStore struct {
    17Ôćĺ	pool  *pgxpool.Pool
    18Ôćĺ	river *river.Client[pgx.Tx]
    19Ôćĺ}
    20Ôćĺ
    21Ôćĺfunc NewPgStore(pool *pgxpool.Pool, riverClient *river.Client[pgx.Tx]) *PgStore {
    22Ôćĺ	return &PgStore{pool: pool, river: riverClient}
    23Ôćĺ}
    24Ôćĺ
    25Ôćĺ// IngestRelease inserts a release and enqueues a notify job in a single transaction.
    26Ôćĺ// Returns an error on unique constraint violation (caller treats as idempotent skip).
    27Ôćĺfunc (s *PgStore) IngestRelease(ctx context.Context, sourceID string, result *IngestionResult) error {
    28Ôćĺ	tx, err := s.pool.Begin(ctx)
    29Ôćĺ	if err != nil {
    30Ôćĺ		return fmt.Errorf("begin tx: %w", err)
    31Ôćĺ	}
    32Ôćĺ	defer tx.Rollback(ctx)
    33Ôćĺ
    34Ôćĺ	// Build raw_data from Metadata + Changelog so nothing is lost.
    35Ôćĺ	raw := make(map[string]string)
    36Ôćĺ	for k, v := range result.Metadata {
    37Ôćĺ		raw[k] = v
    38Ôćĺ	}
    39Ôćĺ	if result.Changelog != "" {
    40Ôćĺ		raw["changelog"] = result.Changelog
    41Ôćĺ	}
    42Ôćĺ	rawData, err := json.Marshal(raw)
    43Ôćĺ	if err != nil {
    44Ôćĺ		return fmt.Errorf("marshal raw_data: %w", err)
    45Ôćĺ	}
    46Ôćĺ
    47Ôćĺ	releaseID := uuid.New().String()
    48Ôćĺ	_, err = tx.Exec(ctx,
    49Ôćĺ		`INSERT INTO releases (id, source_id, version, raw_data, released_at) VALUES ($1, $2, $3, $4, $5)`,
    50Ôćĺ		releaseID, sourceID, result.RawVersion, rawData, result.Timestamp,
    51Ôćĺ	)
    52Ôćĺ	if err != nil {
    53Ôćĺ		return fmt.Errorf("insert release: %w", err)
    54Ôćĺ	}
    55Ôćĺ
    56Ôćĺ	_, err = s.river.InsertTx(ctx, tx, queue.NotifyJobArgs{
    57Ôćĺ		ReleaseID: releaseID,
    58Ôćĺ		SourceID:  sourceID,
    59Ôćĺ	}, nil)
    60Ôćĺ	if err != nil {
    61Ôćĺ		return fmt.Errorf("enqueue job: %w", err)
    62Ôćĺ	}
    63Ôćĺ
    64Ôćĺ	if err := tx.Commit(ctx); err != nil {
    65Ôćĺ		return fmt.Errorf("commit: %w", err)
    66Ôćĺ	}
    67Ôćĺ	return nil
    68Ôćĺ}
