    10Ôćĺ// Service orchestrates ingestion sources and persists results.
    11Ôćĺtype Service struct {
    12Ôćĺ	store ReleaseStore
    13Ôćĺ}
    14Ôćĺ
    15Ôćĺfunc NewService(store ReleaseStore) *Service {
