    18Ôćĺ
    19Ôćĺ// ProcessResults persists raw ingestion results via the store.
    20Ôćĺ// Duplicate releases (unique constraint violations) are logged and skipped, not fatal.
    21Ôćĺfunc (s *Service) ProcessResults(ctx context.Context, sourceID string, sourceName string, results []IngestionResult) error {
    22Ôćĺ	for _, r := range results {
    23Ôćĺ		if err := s.store.IngestRelease(ctx, sourceID, &r); err != nil {
    24Ôćĺ			if isUniqueViolation(err) {
    25Ôćĺ				slog.Debug("duplicate release, skipping", "version", r.RawVersion)
    26Ôćĺ				continue
    27Ôćĺ			}
    28Ôćĺ			return fmt.Errorf("ingest %s: %w", r.RawVersion, err)
    29Ôćĺ		}
    30Ôćĺ		slog.Info("ingested release", "source", sourceName, "version", r.RawVersion)
    31Ôćĺ	}
    32Ôćĺ	return nil
    33Ôćĺ}
    34Ôćĺ
    35Ôćĺ// isUniqueViolation checks if the error is a PostgreSQL unique constraint violation.
    36Ôćĺ// pgx wraps the PG error; we check for the SQLSTATE code 23505.
    37Ôćĺfunc isUniqueViolation(err error) bool {
    38Ôćĺ	return strings.Contains(err.Error(), "23505") ||
    39Ôćĺ		strings.Contains(err.Error(), "unique_violation")
    40Ôćĺ}
