   145Ôćĺ// FetchReleases handles POST /sources/{id}/poll ÔÇö polls upstream for new
   146Ôćĺ// releases, ingests them, and updates last_polled_at.
   147Ôćĺfunc (h *SourcesHandler) FetchReleases(w http.ResponseWriter, r *http.Request) {
   148Ôćĺ	id := r.PathValue("id")
   149Ôćĺ	if id == "" {
   150Ôćĺ		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   151Ôćĺ		return
   152Ôćĺ	}
   153Ôćĺ	src, err := h.store.GetSource(r.Context(), id)
   154Ôćĺ	if err != nil {
   155Ôćĺ		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   156Ôćĺ		return
   157Ôćĺ	}
   158Ôćĺ
   159Ôćĺ	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   160Ôćĺ	if ingestionSrc == nil {
   161Ôćĺ		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   162Ôćĺ		return
   163Ôćĺ	}
