   166Ôćĺ	if err != nil {
   167Ôćĺ		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   168Ôćĺ		_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, err)
   169Ôćĺ		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   170Ôćĺ		return
   171Ôćĺ	}
   172Ôćĺ
   173Ôćĺ	_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, nil)
   174Ôćĺ
   175Ôćĺ	newCount := 0
   176Ôćĺ	if len(results) > 0 && h.ingestionService != nil {
   177Ôćĺ		for _, result := range results {
   178Ôćĺ			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   179Ôćĺ				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
   180Ôćĺ				continue
   181Ôćĺ			}
   182Ôćĺ			newCount++
   183Ôćĺ		}
   184Ôćĺ	}
   185Ôćĺ
   186Ôćĺ	RespondJSON(w, r, http.StatusOK, map[string]int{"new_releases": newCount})
   187Ôćĺ}
