   189Ôćĺ// pollSourceAsync polls a source in the background and updates its poll status.
   190Ôćĺfunc (h *SourcesHandler) pollSourceAsync(sourceID, provider, repository string) {
   191Ôćĺ	ctx := context.Background()
   192Ôćĺ
   193Ôćĺ	ingestionSrc := ingestion.BuildSource(h.httpClient, sourceID, provider, repository)
   194Ôćĺ	if ingestionSrc == nil {
   195Ôćĺ		slog.Warn("async poll: unsupported provider", "source", sourceID, "provider", provider)
   196Ôćĺ		return
   197Ôćĺ	}
   198Ôćĺ
   199Ôćĺ	slog.Info("async poll triggered", "source", sourceID, "provider", provider, "repository", repository)
   200Ôćĺ
   201Ôćĺ	results, err := ingestionSrc.FetchNewReleases(ctx)
   202Ôćĺ	if err != nil {
   203Ôćĺ		slog.Error("async poll failed", "source", sourceID, "err", err)
   204Ôćĺ		_ = h.store.UpdateSourcePollStatus(ctx, sourceID, err)
   205Ôćĺ		return
   206Ôćĺ	}
   207Ôćĺ
   208Ôćĺ	_ = h.store.UpdateSourcePollStatus(ctx, sourceID, nil)
   209Ôćĺ
   210Ôćĺ	if len(results) > 0 && h.ingestionService != nil {
   211Ôćĺ		for _, result := range results {
   212Ôćĺ			if procErr := h.ingestionService.ProcessResults(ctx, sourceID, provider, []ingestion.IngestionResult{result}); procErr != nil {
   213Ôćĺ				slog.Error("async poll: process release failed", "source", sourceID, "version", result.RawVersion, "err", procErr)
   214Ôćĺ			}
   215Ôćĺ		}
   216Ôćĺ	}
   217Ôćĺ}
