    77Ôćĺ	for _, rel := range releases {
    78Ôćĺ		if rel.TagName == "" {
    79Ôćĺ			continue
    80Ôćĺ		}
    81Ôćĺ
    82Ôćĺ		ts, _ := time.Parse(time.RFC3339, rel.ReleasedAt)
    83Ôćĺ
    84Ôćĺ		prerelease := "false"
    85Ôćĺ		if rel.UpcomingRelease {
    86Ôćĺ			prerelease = "true"
    87Ôćĺ		}
