    81Ôćĺ		FROM sessions s JOIN users u ON u.id = s.user_id
    82Ôćĺ		WHERE s.id = $1 AND s.expires_at > NOW()
    83Ôćĺ	`, sessionID).Scan(&u.ID, &u.GitHubID, &u.GitHubLogin, &u.Name, &u.AvatarURL)
    84Ôćĺ	if err != nil {
    85Ôćĺ		return nil, fmt.Errorf("invalid or expired session: %w", err)
    86Ôćĺ	}
