    91Ôćĺfunc (s *SessionStore) DeleteSession(ctx context.Context, cookie string) error {
    92Ôćĺ	sessionID, err := ParseSessionCookie(cookie, s.secret)
    93Ôćĺ	if err != nil {
    94Ôćĺ		return err
    95Ôćĺ	}
