   100Ôćĺ// CleanupExpired removes all expired sessions. Intended to be called periodically.
   101Ôćĺfunc (s *SessionStore) CleanupExpired(ctx context.Context) (int64, error) {
   102Ôćĺ	tag, err := s.pool.Exec(ctx, `DELETE FROM sessions WHERE expires_at < NOW()`)
   103Ôćĺ	if err != nil {
   104Ôćĺ		return 0, err
