   106Ôćĺ	return tag.RowsAffected(), nil
   107Ôćĺ}
   108Ôćĺ
   109Ôćĺ// RunCleanupLoop deletes expired sessions every hour until ctx is cancelled.
   110Ôćĺfunc (s *SessionStore) RunCleanupLoop(ctx context.Context) {
   111Ôćĺ	ticker := time.NewTicker(1 * time.Hour)
   112Ôćĺ	defer ticker.Stop()
   113Ôćĺ	for {
   114Ôćĺ		select {
   115Ôćĺ		case <-ctx.Done():
