   117Ôćĺ		case <-ticker.C:
   118Ôćĺ			if n, err := s.CleanupExpired(ctx); err != nil {
   119Ôćĺ				slog.Error("session cleanup failed", "err", err)
   120Ôćĺ			} else if n > 0 {
   121Ôćĺ				slog.Info("cleaned up expired sessions", "count", n)
   122Ôćĺ			}
   123Ôćĺ		}
   124Ôćĺ	}
   125Ôćĺ}
