   249Ôćĺ// ParseDependencies parses the LLM response into ScannedDependency structs.
   250Ôćĺ// Handles raw JSON arrays and markdown-fenced JSON.
   251Ôćĺfunc ParseDependencies(raw []byte) ([]models.ScannedDependency, error) {
   252Ôćĺ	text := strings.TrimSpace(string(raw))
   253Ôćĺ
   254Ôćĺ	// Strip markdown code fences if present
   255Ôćĺ	if strings.HasPrefix(text, "```") {
   256Ôćĺ		lines := strings.Split(text, "\n")
   257Ôćĺ		if len(lines) > 2 {
   258Ôćĺ			// Remove first and last lines (``` markers)
   259Ôćĺ			lines = lines[1 : len(lines)-1]
   260Ôćĺ			// If last line is also ```, it was already removed
   261Ôćĺ			if len(lines) > 0 && strings.TrimSpace(lines[len(lines)-1]) == "```" {
   262Ôćĺ				lines = lines[:len(lines)-1]
   263Ôćĺ			}
   264Ôćĺ			text = strings.Join(lines, "\n")
   265Ôćĺ		}
   266Ôćĺ	}
   267Ôćĺ
   268Ôćĺ	var deps []models.ScannedDependency
   269Ôćĺ	if err := json.Unmarshal([]byte(text), &deps); err != nil {
   270Ôćĺ		return nil, fmt.Errorf("parse dependencies JSON: %w\nraw: %s", err, text)
   271Ôćĺ	}
   272Ôćĺ	return deps, nil
   273Ôćĺ}
