    69Ôćĺ	raw = strings.TrimSuffix(raw, "/")
    70Ôćĺ
    71Ôćĺ	parts := strings.SplitN(raw, "/", 3)
    72Ôćĺ	if len(parts) < 2 || parts[0] == "" || parts[1] == "" {
    73Ôćĺ		return "", "", fmt.Errorf("invalid repo URL: expected 'owner/repo', got %q", raw)
    74Ôćĺ	}
