    78Ôćĺ// FetchDependencyFiles fetches the repo tree, identifies dependency files, and returns their contents.
    79Ôćĺfunc (s *Scanner) FetchDependencyFiles(ctx context.Context, owner, repo string) ([]DependencyFile, error) {
