   141Ôćĺfunc (s *Scanner) getFileContent(ctx context.Context, owner, repo, path string) (string, error) {
   142Ôćĺ	url := fmt.Sprintf("%s/repos/%s/%s/contents/%s", s.baseURL, owner, repo, path)
   143Ôćĺ	var result struct {
