   150Ôćĺ	if result.Encoding == "base64" {
   151Ôćĺ		decoded, err := base64.StdEncoding.DecodeString(strings.ReplaceAll(result.Content, "\n", ""))
   152Ôćĺ		if err != nil {
   153Ôćĺ			return "", fmt.Errorf("decode base64: %w", err)
   154Ôćĺ		}
   155Ôćĺ		return string(decoded), nil
   156Ôćĺ	}
   157Ôćĺ	return result.Content, nil
