   160Ôćĺfunc (s *Scanner) doGet(ctx context.Context, url string, out any) error {
   161Ôćĺ	req, err := http.NewRequestWithContext(ctx, "GET", url, nil)
   162Ôćĺ	if err != nil {
   163Ôćĺ		return err
   164Ôćĺ	}
   165Ôćĺ	if s.token != "" {
   166Ôćĺ		req.Header.Set("Authorization", "Bearer "+s.token)
   167Ôćĺ	}
   168Ôćĺ	req.Header.Set("Accept", "application/vnd.github+json")
   169Ôćĺ	resp, err := s.client.Do(req)
   170Ôćĺ	if err != nil {
   171Ôćĺ		return err
   172Ôćĺ	}
   173Ôćĺ	defer resp.Body.Close()
   174Ôćĺ	if resp.StatusCode != http.StatusOK {
   175Ôćĺ		return fmt.Errorf("GitHub API returned %d for %s", resp.StatusCode, url)
   176Ôćĺ	}
   177Ôćĺ	return json.NewDecoder(resp.Body).Decode(out)
   178Ôćĺ}
