    77Ôćĺ// GitHub handles GET /discover/github ÔÇö searches GitHub repositories.
    78Ôćĺfunc (h *DiscoverHandler) GitHub(w http.ResponseWriter, r *http.Request) {
    79Ôćĺ	q := r.URL.Query().Get("q")
    80Ôćĺ	language := r.URL.Query().Get("language")
    81Ôćĺ
    82Ôćĺ	cacheKey := fmt.Sprintf("github:%s:%s", q, language)
    83Ôćĺ	if items, ok := h.getCached(cacheKey); ok {
    84Ôćĺ		RespondJSON(w, r, http.StatusOK, items)
    85Ôćĺ		return
    86Ôćĺ	}
    87Ôćĺ
    88Ôćĺ	// Approximate GitHub Trending: search for repos with recent star activity.
    89Ôćĺ	// Default query filters to repos created in the last 7 days, sorted by stars.
    90Ôćĺ	since := time.Now().AddDate(0, 0, -7).Format("2006-01-02")
    91Ôćĺ	searchQ := q
    92Ôćĺ	if searchQ == "" {
    93Ôćĺ		searchQ = fmt.Sprintf("created:>%s stars:>10", since)
    94Ôćĺ	}
    95Ôćĺ	if language != "" {
    96Ôćĺ		searchQ = fmt.Sprintf("%s language:%s", searchQ, language)
    97Ôćĺ	}
    98Ôćĺ
    99Ôćĺ	u, _ := url.Parse(h.githubURL + "/search/repositories")
   100Ôćĺ	params := url.Values{}
   101Ôćĺ	params.Set("q", searchQ)
   102Ôćĺ	params.Set("sort", "stars")
   103Ôćĺ	params.Set("order", "desc")
   104Ôćĺ	params.Set("per_page", "25")
   105Ôćĺ	u.RawQuery = params.Encode()
   106Ôćĺ
   107Ôćĺ	req, err := http.NewRequestWithContext(r.Context(), http.MethodGet, u.String(), nil)
   108Ôćĺ	if err != nil {
   109Ôćĺ		RespondError(w, r, http.StatusInternalServerError, "request_error", "failed to build GitHub request")
   110Ôćĺ		return
   111Ôćĺ	}
   112Ôćĺ	resp, err := h.client.Do(req)
   113Ôćĺ	if err != nil {
   114Ôćĺ		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach GitHub API")
   115Ôćĺ		return
   116Ôćĺ	}
   117Ôćĺ	defer resp.Body.Close()
   118Ôćĺ
   119Ôćĺ	if resp.StatusCode != http.StatusOK {
   120Ôćĺ		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("GitHub API returned %d", resp.StatusCode))
   121Ôćĺ		return
   122Ôćĺ	}
   123Ôćĺ
   124Ôćĺ	var ghResp struct {
   125Ôćĺ		Items []struct {
   126Ôćĺ			Name        string `json:"name"`
   127Ôćĺ			FullName    string `json:"full_name"`
   128Ôćĺ			Description string `json:"description"`
   129Ôćĺ			Stars       int    `json:"stargazers_count"`
   130Ôćĺ			Language    string `json:"language"`
   131Ôćĺ			HTMLURL     string `json:"html_url"`
   132Ôćĺ			Owner       struct {
   133Ôćĺ				AvatarURL string `json:"avatar_url"`
   134Ôćĺ			} `json:"owner"`
   135Ôćĺ		} `json:"items"`
   136Ôćĺ	}
   137Ôćĺ	if err := json.NewDecoder(resp.Body).Decode(&ghResp); err != nil {
   138Ôćĺ		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse GitHub response")
   139Ôćĺ		return
   140Ôćĺ	}
   141Ôćĺ
   142Ôćĺ	items := make([]DiscoverItem, 0, len(ghResp.Items))
   143Ôćĺ	for _, repo := range ghResp.Items {
   144Ôćĺ		items = append(items, DiscoverItem{
   145Ôćĺ			Name:        repo.Name,
   146Ôćĺ			FullName:    repo.FullName,
   147Ôćĺ			Description: repo.Description,
